# Bicep: role assignment at resource group scope
targetScope = 'resourceGroup'

param principalId string
// Key Vault Secrets User role definition ID
var kvSecretsUserRoleId = '4633458b-17de-408a-b874-0445c86b69e6'

resource kvRoleAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(resourceGroup().id, principalId, kvSecretsUserRoleId)
  properties: {
    roleDefinitionId: subscriptionResourceId(
      'Microsoft.Authorization/roleDefinitions', kvSecretsUserRoleId)
    principalId: principalId
    principalType: 'ServicePrincipal'
  }
}

# Terraform: role assignment
# resource "azurerm_role_assignment" "example" {
#   scope                = azurerm_resource_group.prod.id
#   role_definition_name = "Contributor"
#   principal_id         = azuread_group.devops.object_id
# }

# ARM JSON template fragment
# {
#   "type": "Microsoft.Authorization/roleAssignments",
#   "apiVersion": "2022-04-01",
#   "name": "[guid(resourceGroup().id, parameters('principalId'), variables('roleId'))]",
#   "properties": {
#     "roleDefinitionId": "[concat('/subscriptions/', subscription().subscriptionId,
#       '/providers/Microsoft.Authorization/roleDefinitions/', variables('roleId'))]",
#     "principalId": "[parameters('principalId')]",
#     "principalType": "ServicePrincipal"
#   }
# }

# Check current role assignment count in a subscription
$assignmentCount = (Get-AzRoleAssignment).Count
Write-Host "Current: $assignmentCount / 4000"

# Break down assignments by scope level to find where most assignments live
Get-AzRoleAssignment | ForEach-Object {
    $parts = $_.Scope.TrimStart('/').Split('/')
    $level = if ($_.Scope -match 'managementGroups') { 'MgGroup' }
             elseif ($parts.Count -eq 2) { 'Subscription' }
             elseif ($parts.Count -eq 4) { 'ResourceGroup' }
             else { 'Resource' }
    [PSCustomObject]@{ Level = $level }
} | Group-Object Level | Select-Object Name, Count | Sort-Object Count -Descending

# Find principals with the most individual assignments (candidates for group consolidation)
Get-AzRoleAssignment | Group-Object DisplayName |
    Select-Object Name, Count | Sort-Object Count -Descending | Select-Object -First 20

# Replace individual user assignments with a group assignment:
# 1. Create the group
$g = New-MgGroup -DisplayName "Prod Contributors" -MailEnabled:$false -SecurityEnabled:$true -MailNickname "prod-contributors"
# 2. Add the users to the group
$userIds | ForEach-Object { New-MgGroupMember -GroupId $g.Id -DirectoryObjectId $_ }
# 3. Assign the role to the group
New-AzRoleAssignment -ObjectId $g.Id -RoleDefinitionName 'Contributor' -Scope $rgScope
# 4. Remove the individual assignments
$userIds | ForEach-Object { Remove-AzRoleAssignment -ObjectId $_ -RoleDefinitionName 'Contributor' -Scope $rgScope }
